svg.script:
//
(function() {
  var svg = document.getElementById('root');
  var ns  = 'http://www.w3.org/2000/svg';

  document.getElementById('dark-toggle').addEventListener('click', function() {
    var thumb = document.getElementById('tthumb'), lbl = document.getElementById('tlabel');
    if (svg.classList.toggle('dark')) { thumb.setAttribute('cx','52'); lbl.textContent='Light'; swapFills(true); }
    else                              { thumb.setAttribute('cx','16'); lbl.textContent='Dark';  swapFills(false); }
  });
  function swapFills(dark) {
    svg.querySelectorAll('path[fill]').forEach(function(p) {
      var f = p.getAttribute('fill') || '';
      var m = f.match(/url\(#(a[1-5])(d?)\)/);
      if (!m) return;
      p.setAttribute('fill', dark ? 'url(#' + m[1] + 'd)' : 'url(#' + m[1] + ')');
    });
  }
  document.getElementById('print-toggle').addEventListener('click', function() {
    var thumb = document.getElementById('pthumb'), lbl = document.getElementById('plabel');
    if (svg.classList.toggle('print')) { thumb.setAttribute('cx','52'); lbl.textContent='Screen'; }
    else                               { thumb.setAttribute('cx','16'); lbl.textContent='Print';  }
  });

  var quarters = ["Q1 '22","Q2 '22","Q3 '22","Q4 '22","Q1 '23","Q2 '23","Q3 '23","Q4 '23"];
  var xs = [68,180,291,403,515,627,738,850];
  var colW = 50;
  var series = [
    { label:'Cyan',    color:'#20D0E0', vals:[32,38,41,48,52,61,68,72] },
    { label:'Emerald', color:'#18A870', vals:[28,31,35,40,44,49,55,62] },
    { label:'Amber',   color:'#E8A020', vals:[18,22,25,29,25,28,31,35] },
    { label:'Rose',    color:'#E04060', vals:[12,15,18,14,17,20,16,22] },
    { label:'Other',   color:'#607080', vals:[10,13,11,15,13,17,15,19] },
  ];
  var totals = xs.map(function(_,qi){ return series.reduce(function(s,sr){ return s+sr.vals[qi]; },0); });

  var hitLayer = document.getElementById('hit-layer');
  var tipLayer = document.getElementById('tip-layer');
  var allTips  = {};

  function el(tag, attrs) {
    var e = document.createElementNS(ns, tag);
    Object.keys(attrs).forEach(function(k){ e.setAttribute(k, attrs[k]); });
    return e;
  }

  xs.forEach(function(x, qi) {
    var bw=168, bh=146, hw=bw/2, bCx=x, bCy=200;
    if (bCx-hw < 72)  bCx = 72+hw;
    if (bCx+hw > 846) bCx = 846-hw;

    var tipG = el('g', { 'class':'tip', id:'tip_'+qi });
    tipLayer.appendChild(tipG);
    allTips[qi] = tipG;

    tipG.appendChild(el('rect', { x:bCx-hw, y:bCy-12, width:bw, height:bh+12, rx:10, 'class':'bub-bg', filter:'url(#tipshadow)' }));
    tipG.appendChild(el('rect', { x:bCx-hw, y:bCy-12, width:bw, height:bh+12, rx:10, 'class':'bub-bdr' }));

    var qLbl = el('text', { x:bCx, y:bCy+5, 'text-anchor':'middle', 'dominant-baseline':'central', 'class':'bub-lbl' });
    qLbl.textContent = quarters[qi];
    tipG.appendChild(qLbl);
    tipG.appendChild(el('line', { x1:bCx-hw+8, y1:bCy+15, x2:bCx+hw-8, y2:bCy+15, 'class':'tip-div' }));

    series.forEach(function(s, si) {
      var rowY = bCy+28+si*18;
      tipG.appendChild(el('circle', { cx:bCx-hw+14, cy:rowY, r:4, fill:s.color }));
      var sLbl = el('text', { x:bCx-hw+24, y:rowY, 'dominant-baseline':'central', 'class':'bub-lbl' });
      sLbl.textContent = s.label;
      tipG.appendChild(sLbl);
      var sVal = el('text', { x:bCx+hw-8, y:rowY, 'text-anchor':'end', 'dominant-baseline':'central', 'class':'bub-val', 'font-size':'11' });
      sVal.textContent = '$'+s.vals[qi]+'M';
      tipG.appendChild(sVal);
    });

    tipG.appendChild(el('line', { x1:bCx-hw+8, y1:bCy+118, x2:bCx+hw-8, y2:bCy+118, 'class':'tip-div' }));
    var totLbl = el('text', { x:bCx-hw+8, y:bCy+130, 'dominant-baseline':'central', 'class':'bub-lbl' });
    totLbl.textContent = 'Total';
    tipG.appendChild(totLbl);
    var totVal = el('text', { x:bCx+hw-8, y:bCy+130, 'text-anchor':'end', 'dominant-baseline':'central', 'class':'bub-val' });
    totVal.textContent = '$'+totals[qi]+'M';
    tipG.appendChild(totVal);

    var hitX1 = Math.max(68, x-colW), hitX2 = Math.min(850, x+colW);
    var hit = el('rect', { x:hitX1, y:100, width:hitX2-hitX1, height:404, fill:'transparent', cursor:'crosshair' });
    hitLayer.appendChild(hit);

    var ch = document.getElementById('ch'+qi);
    hit.addEventListener('mouseenter', function() { allTips[qi].style.opacity='1'; if(ch) ch.style.opacity='1'; });
    hit.addEventListener('mouseleave', function() { allTips[qi].style.opacity='';  if(ch) ch.style.opacity=''; });
  });

  /* ── URL param: ?theme=dark|light sets initial mode ── */
  (function() {
    var params = new URLSearchParams(window.location.search);
    if (params.get('theme') === 'dark') {
      svg.classList.add('dark');
      var thumb = document.getElementById('tthumb'), lbl = document.getElementById('tlabel');
      if (thumb) thumb.setAttribute('cx','52');
      if (lbl)   lbl.textContent = 'Light';
      swapFills(true);
    }
  })();

})();
//
